DROP TABLE IF EXISTS `lab_paper`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `lab_paper` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `type` int NOT NULL COMMENT '0-期刊，1-会议，2-预印本，3-专利，4-软著，5-标准，6-专著',
  `title` varchar(255) NOT NULL COMMENT '标题',
  `author` varchar(255) NOT NULL COMMENT '可能有多人，用逗号或分号隔开',
  `date` date NOT NULL COMMENT '年，年月，年月日',
  `publication` varchar(255) NOT NULL COMMENT '论文集/期刊名称/预印本网站、授权单位、出版单位',
  `conf` varchar(255) DEFAULT NULL COMMENT '可空，会议名称',
  `number` varchar(255) DEFAULT NULL COMMENT '可空，期刊卷（期）号、（专利、软著）编号、标准编号',
  `place` varchar(255) DEFAULT NULL COMMENT '可空，会议地点',
  `publisher` varchar(255) DEFAULT NULL COMMENT '可空，会议论文集出版社',
  `page` varchar(255) DEFAULT NULL COMMENT '可空，页码，可能有多种写法（11-18）、（11）、（11-18, 21）',
  `doi` varchar(255) DEFAULT NULL COMMENT '可空，DOI号，用户只需填写doi.org/后面的部分，在前端提示',
  `url` varchar(255) DEFAULT NULL COMMENT '可空，其它链接',
  `desc` varchar(255) DEFAULT NULL COMMENT '可空，其它信息，例如会议ccf级别、会议简称等可能将来用于扩展功能的信息',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

